/*
 * The bluetooth to device link:
 * Old BTLE protocol docs from TODO, merge in above and make real docs...
 * use protocol buffers, and NanoPB
 * messages from device to phone:
 * POSITION_UPDATE (..., time)
 * TEXT_RECEIVED(from, text, time)
 * OPAQUE_RECEIVED(from, payload, time) (for signal messages or other applications)
 * messages from phone to device:
 * SET_MYID(id, human readable long, human readable short) (send down the unique ID
 * string used for this node, a human readable string shown for that id, and a very
 * short human readable string suitable for oled screen) SEND_OPAQUE(dest, payload)
 * (for signal messages or other applications) SEND_TEXT(dest, text) Get all
 * nodes() (returns list of nodes, with full info, last time seen, loc, battery
 * level etc) SET_CONFIG (switches device to a new set of radio params and
 * preshared key, drops all existing nodes, force our node to rejoin this new group)
 * Full information about a node on the mesh
 */
struct  Meshtastic__NodeInfo
{
  ProtobufCMessage base;
  /*
   * The node number
   */
  uint32_t num;
  /*
   * The user info for this node
   */
  Meshtastic__User *user;
  /*
   * This position data. Note: before 1.2.14 we would also store the last time we've heard from this node in position.time, that is no longer true.
   * Position.time now indicates the last time we received a POSITION from that node.
   */
  Meshtastic__Position *position;
  /*
   * Returns the Signal-to-noise ratio (SNR) of the last received message,
   * as measured by the receiver. Return SNR of the last received message in dB
   */
  float snr;
  /*
   * Set to indicate the last time we received a packet from this node
   */
  uint32_t last_heard;
  /*
   * The latest device metrics for the node.
   */
  Meshtastic__DeviceMetrics *device_metrics;
  /*
   * local channel index we heard that node on. Only populated if its not the default channel.
   */
  uint32_t channel;
  /*
   * True if we witnessed the node over MQTT instead of LoRA transport
   */
  protobuf_c_boolean via_mqtt;
  /*
   * True if node is in our favorites list
   * Persists between NodeDB internal clean ups
   */
  protobuf_c_boolean is_favorite;
  Meshtastic__NodeInfo__HopsAwayCase _hops_away_case;
  union {
    /*
     * Number of hops away from us this node is (0 if adjacent)
     */
    uint32_t hops_away;
  };
};
