/*
 * Packets from the radio to the phone will appear on the fromRadio characteristic.
 * It will support READ and NOTIFY. When a new packet arrives the device will BLE notify?
 * It will sit in that descriptor until consumed by the phone,
 * at which point the next item in the FIFO will be populated.
 */
struct  Meshtastic__FromRadio
{
  ProtobufCMessage base;
  /*
   * The packet id, used to allow the phone to request missing read packets from the FIFO,
   * see our bluetooth docs
   */
  uint32_t id;
  Meshtastic__FromRadio__PayloadVariantCase payload_variant_case;
  union {
    /*
     * One packet is sent for each channel
     */
    Meshtastic__Channel *channel;
    /*
     * Notification message to the client
     */
    Meshtastic__ClientNotification *clientnotification;
    /*
     * Include a part of the config (was: RadioConfig radio)
     */
    Meshtastic__Config *config;
    /*
     * File system manifest messages
     */
    Meshtastic__FileInfo *fileinfo;
    /*
     * Set to send debug console output over our protobuf stream
     */
    Meshtastic__LogRecord *log_record;
    /*
     * Device metadata message
     */
    Meshtastic__DeviceMetadata *metadata;
    /*
     * Include module config
     */
    Meshtastic__ModuleConfig *moduleconfig;
    /*
     * MQTT Client Proxy Message (device sending to client / phone for publishing to MQTT)
     */
    Meshtastic__MqttClientProxyMessage *mqttclientproxymessage;
    /*
     * Tells the phone what our node number is, can be -1 if we've not yet joined a mesh.
     * NOTE: This ID must not change - to keep (minimal) compatibility with <1.2 version of android apps.
     */
    Meshtastic__MyNodeInfo *my_info;
    /*
     * One packet is sent for each node in the on radio DB
     * starts over with the first node in our DB
     */
    Meshtastic__NodeInfo *node_info;
    /*
     * Log levels, chosen to match python logging conventions.
     */
    Meshtastic__MeshPacket *packet;
    /*
     * Queue status info
     */
    Meshtastic__QueueStatus *queuestatus;
    /*
     * File Transfer Chunk
     */
    Meshtastic__XModem *xmodempacket;
    /*
     * Sent as true once the device has finished sending all of the responses to want_config
     * recipient should check if this ID matches our original request nonce, if
     * not, it means your config responses haven't started yet.
     * NOTE: This ID must not change - to keep (minimal) compatibility with <1.2 version of android apps.
     */
    uint32_t config_complete_id;
    /*
     * Sent to tell clients the radio has just rebooted.
     * Set to true if present.
     * Not used on all transports, currently just used for the serial console.
     * NOTE: This ID must not change - to keep (minimal) compatibility with <1.2 version of android apps.
     */
    protobuf_c_boolean rebooted;
  };
};
